      </div>

      <section className="dashboard-cards-container">
        <DashboardCard title="Mùa vụ" value={summary.seasonCount} rating={evaluateMetric('ponds', summary.seasonCount)} description="Số mùa vụ" />
        <DashboardCard title="Tổng chi phí" value={summary.totalExpense} rating={evaluateMetric('alerts', summary.totalExpense)} description={formatCurrency(summary.totalExpense)} />
      </section>

      <div className="recent-section section-stack">
        <h2>�xR Tính nĒng chính</h2>
        <div className="info-boxes">
          <div className="info-box">
